    57→      trackSeverinoEvent("cadastro_do_salao", {
    58→        descricao: `Salão cadastrado: ${formData.nomeFantasia} (ID: ${result.salon.id})`,
    59→        nomeSalao: formData.nomeFantasia,
    60→        salonId: result.salon.id,
    61→      });
    62→
    63→      toast.success("Salão cadastrado com sucesso e adicionado à sua rede!");
    64→      navigate("/admin/salons");
    65→    } catch (error: unknown) {
    66→      const errorMessage =
    67→        (error as { response?: { data?: { message?: string } } })?.response?.data?.message ||
