import { useState, useEffect, useCallback } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { EasySalonLayout } from "@/components/layout/EasySalonLayout";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { ArrowLeft } from "lucide-react";
import { getAdminNavItems } from "@/config/navigation";
import { useAuth } from "@/contexts/AuthContext";
import { LoadingSpinner } from "@/components/ui/loading-spinner";
import { toast } from "sonner";
import { salonService } from "@/services/salonService";
import { UpdateSalonDto } from "@/types/salon";
import { SalonForm, SalonFormData, SalonFormErrors } from "@/components/forms/SalonForm";
import { validateSalonForm } from "@/components/forms/SalonForm.types";

export default function EditSalonPage() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const { id } = useParams<{ id: string }>();

  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [formData, setFormData] = useState<SalonFormData>({
    nomeFantasia: "",
    razaoSocial: "",
    cnpj: "",
    telefoneComercial: "",
    emailContato: "",
    nomeLinkUtil: "",
    urlLinkUtil: "",
    timezone: "America/Sao_Paulo",
  });
  const [active, setActive] = useState(true);
  const [formErrors, setFormErrors] = useState<SalonFormErrors>({});

  const loadSalon = useCallback(async (): Promise<void> => {
    if (!id) {
      toast.error("ID do salão não encontrado");
      navigate("/admin/salons");
      return;
    }

    try {
      setIsLoading(true);
      const salon = await salonService.getById(id);
      setFormData({
        nomeFantasia: salon.name ?? "",
        razaoSocial: salon.responsible ?? "",
        cnpj: salon.cnpj ?? "",
        telefoneComercial: salon.phone ?? "",
        emailContato: salon.email ?? "",
        nomeLinkUtil: salon.websiteName ?? "",
        urlLinkUtil: salon.websiteUrl ?? "",
        timezone: salon.timezone ?? "America/Sao_Paulo",
      });
      setActive(salon.active ?? true);
    } catch {
      toast.error("Erro ao carregar dados do salão");
      navigate("/admin/salons");
    } finally {
      setIsLoading(false);
    }
  }, [id, navigate]);

  useEffect(() => {
    void loadSalon();
  }, [loadSalon]);

  const handleErrorChange = (field: keyof SalonFormData): void => {
    setFormErrors((prev) => {
      const next = { ...prev };
      delete next[field];
      return next;
    });
  };

  const handleSave = async (): Promise<void> => {
    const errors = validateSalonForm(formData);
    if (Object.keys(errors).length > 0) {
      setFormErrors(errors);
      return;
    }

    if (!id) return;

    setIsSaving(true);

    try {
      const updateData: UpdateSalonDto = {
        name: formData.nomeFantasia.trim(),
        responsible: formData.razaoSocial.trim() || undefined,
        cnpj: formData.cnpj ? salonService.formatCNPJ(formData.cnpj) : undefined,
        phone: salonService.formatPhone(formData.telefoneComercial),
        email: formData.emailContato.trim() || undefined,
        timezone: formData.timezone,
        websiteName: formData.nomeLinkUtil.trim() || undefined,
        websiteUrl: formData.urlLinkUtil.trim() || undefined,
        active,
      };

      await salonService.update(id, updateData);
      toast.success("Salão atualizado com sucesso!");
      navigate("/admin/salons");
    } catch (error: unknown) {
      const errorMessage =
        (error as { response?: { data?: { message?: string } } })?.response?.data?.message ||
        "Erro ao salvar as alterações do salão";
      toast.error(errorMessage);
    } finally {
      setIsSaving(false);
    }
  };

  if (isLoading) {
    return (
      <EasySalonLayout
        sideNavItems={getAdminNavItems(user?.role || "Easy Salon")}
        sideNavTitle="Easy Salon"
        sideNavSubtitle="Área Administrativa"
      >
        <div className="flex items-center justify-center h-64">
          <LoadingSpinner size="md" />
        </div>
      </EasySalonLayout>
    );
  }

  return (
    <EasySalonLayout
      sideNavItems={getAdminNavItems(user?.role || "Easy Salon")}
      sideNavTitle="Easy Salon"
      sideNavSubtitle="Área Administrativa"
    >
      <div className="flex items-center gap-4 mb-6">
        <Button variant="secondary" size="icon" onClick={() => navigate("/admin/salons")}>
          <ArrowLeft className="h-5 w-5" />
        </Button>
        <div>
          <h1 className="page-title">Editar Salão</h1>
          <p className="text-[13px] text-muted-foreground">Atualize as informações do salão</p>
        </div>
      </div>

      <div className="bg-card border border-border rounded-lg">
        <div className="p-6">
          <SalonForm
            data={formData}
            onChange={setFormData}
            errors={formErrors}
            onErrorChange={handleErrorChange}
            disabled={isSaving}
          />

          <div className="flex items-center justify-between mt-8 pt-6 border-t">
            <div className="flex items-center gap-2">
              <Switch
                id="edit-salon-active"
                checked={active}
                onCheckedChange={setActive}

