import { ReactNode } from "react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
interface PageHeaderProps {
  title: string;
  disabledActions?: boolean;
  subtitle?: string;
  action?: {
    label: string;
    onClick: () => void;
    variant?: "primary" | "secondary";
    className?: string;
  };
  children?: ReactNode;
}
export function PageHeader({
  title,
  subtitle,
  action,
  children,
  disabledActions = false,
}: PageHeaderProps) {
  return (
    <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-3 md:gap-4 mb-6"> {/* RESP: Breakpoint md e gaps responsivos */}
      <div>
        <h1 className="text-page-title text-foreground">{title}</h1>
        {subtitle && <p className="text-body text-muted-foreground mt-1">{subtitle}</p>}
      </div>

      <div className="flex items-center gap-3 w-full md:w-auto">
        {children}
        {action && (
          <Button
            disabled={disabledActions}
            onClick={action.onClick}
            variant={action.variant === "secondary" ? "outline" : "default"}
            className={cn("w-full md:w-auto", action.className)}
          >
            {action.label}
          </Button>
        )}
      </div>
    </div>
  );
}

