import { SalonForm, SalonFormData, SalonFormErrors, SALON_FORM_INITIAL_DATA } from "@/components/forms/SalonForm";
import { validateSalonForm } from "@/components/forms/SalonForm.types";
import { trackSeverinoEvent } from "@/services/severinoService";

export default function CreateSalonPage() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [isLoading, setIsLoading] = useState(false);
  const [formData, setFormData] = useState<SalonFormData>(SALON_FORM_INITIAL_DATA);
  const [formErrors, setFormErrors] = useState<SalonFormErrors>({});

  const handleErrorChange = (field: keyof SalonFormData): void => {
    setFormErrors((prev) => {
      const next = { ...prev };
      delete next[field];
      return next;
    });
  };

  const handleCreateSalon = async (): Promise<void> => {
    const errors = validateSalonForm(formData);
    if (Object.keys(errors).length > 0) {
      setFormErrors(errors);
