                placeholder="000.000.000-00"
                maxLength={14}
                disabled={loading}
              />
            </div>

            <div className="flex items-center space-x-2 pt-6">
              <Switch
                id="active"
                checked={userData.active}
                onCheckedChange={(checked) => handleInputChange("active", checked)}
                disabled={loading}
              />
