                Usuário ativo
              </Label>
            </div>
          </div>

          {/* Description Field */}
          <div className="flex flex-col gap-[4px]">
            <Label htmlFor="description">Descrição</Label>
            <Textarea
              id="description"
              value={userData.description || ""}
              onChange={(e) => handleInputChange("description", e.target.value)}
              placeholder="Informações adicionais sobre o usuário"
              disabled={loading}
              className="resize-none"
              rows={4}
              maxLength={500}
            />
          </div>

          {hasRoleChanged() && (
            <Alert variant="warning">
              <AlertTriangle className="h-4 w-4" />
              <AlertDescription>
                <p className="font-medium mb-1">Alteração de Perfil</p>
                <p className="text-body mb-1">
                  O perfil será alterado de <strong>{userService.getRoleLabel(originalUser!.role)}</strong> para <strong>{userService.getRoleLabel(userData.role!)}</strong>.
                </p>
                <p className="text-body">Esta alteração afetará as permissões do usuário no sistema.</p>
              </AlertDescription>
            </Alert>
