import { userService } from "@/services/userService";
import { tenantService } from "@/services/tenantService";
import { User, UpdateUserDto, UserRole } from "@/types/user";
import { Tenant } from "@/types/tenant";
import { LoadingSpinner } from "@/components/ui/loading-spinner";
import { Building2 as Building2, Globe as Globe, Calendar as Calendar, CircleCheck as CheckCircle, CircleX as XCircle, AlertTriangle as AlertTriangle, ArrowLeft } from "lucide-react";
import { Alert, AlertDescription } from "@/components/ui/alert";

export default function EditUserPage() {
  const { user } = useAuth();
  const { id } = useParams();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(true);
  const [originalUser, setOriginalUser] = useState<User | null>(null);
  const [tenantData, setTenantData] = useState<Tenant | null>(null);
  const [userData, setUserData] = useState<UpdateUserDto & { birthDate?: string; cpf?: string; description?: string }>({
    name: "",
    email: "",
    birthDate: "",
    phone: "",
    whatsapp: "",
    cpf: "",
    description: "",
    active: true
  });

  useEffect(() => {
    fetchUser();
  }, [id]);

  const fetchUser = async () => {
    if (!id) return;

    setFetching(true);
    try {
      const user = await userService.getById(id);
      setOriginalUser(user);
      setUserData({
        name: user.name,
        email: user.email,
        birthDate: (user as any).birthDate || "",
        phone: user.phone || "",
        whatsapp: user.whatsapp || "",
        cpf: (user as any).cpf || "",
        description: (user as any).description || "",
        active: user.active
      });

      // Se o usuário for tenant admin, buscar dados do tenant
      if (user.role === UserRole.TENANT_ADMIN && user.tenantId) {
        try {
          const tenant = await tenantService.getById(user.tenantId);
          setTenantData(tenant);
        } catch (error) {
          // Não mostrar erro ao usuário, apenas não exibir os dados do tenant
        }
      }
    } catch (error: any) {
      toast.error("Algo deu errado. Tente novamente.");
      navigate("/admin/users");
    } finally {
      setFetching(false);
    }
  };

  const handleInputChange = (field: keyof (UpdateUserDto & { birthDate?: string; cpf?: string; description?: string }), value: any) => {
    setUserData(prev => ({ ...prev, [field]: value }));
  };

  const formatCPF = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 11) {
      return numbers
        .replace(/(\d{3})(\d)/, '$1.$2')
        .replace(/(\d{3})(\d)/, '$1.$2')
        .replace(/(\d{3})(\d{1,2})/, '$1-$2');
    }
    return value;
  };

  const validateForm = () => {
    if (!userData.name?.trim()) {
      toast.error("Nome completo é obrigatório");
      return false;
    }
    if (!userData.email?.trim()) {
      toast.error("Email é obrigatório");
      return false;
    }
    // Validação de email
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(userData.email)) {
      toast.error("Email inválido");
      return false;
    }
    return true;
  };

  const handleSave = async () => {
    if (!validateForm() || !id) return;

    setLoading(true);
    try {
      // Prepare data for API - remove formatting from phone numbers
      const dataToSend: UpdateUserDto = {
        name: userData.name.trim(),
        email: userData.email.trim(),
        active: userData.active
      };

      // Only include optional fields if they have values
      if (userData.birthDate) {
        dataToSend.birthDate = userData.birthDate;
      }

      if (userData.whatsapp) {
        // Remove formatting from whatsapp/phone
        const cleanPhone = userData.whatsapp.replace(/\D/g, '');
        dataToSend.whatsapp = cleanPhone;
        dataToSend.phone = cleanPhone; // Set both fields with same value
      }

      if (userData.cpf) {
        // CPF should be in format XXX.XXX.XXX-XX
        dataToSend.cpf = userData.cpf;
      }

      // Always include description field, even if empty
      dataToSend.description = userData.description?.trim() || "";

      await userService.update(id, dataToSend);
      toast.success("Usuário atualizado com sucesso!");
      navigate("/admin/users");
    } catch (error: any) {
      if (error.response?.data?.message) {
        toast.error(`Erro ao atualizar usuário: ${error.response.data.message}`);
      } else {
        toast.error("Algo deu errado. Tente novamente.");
      }
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = () => {
    navigate("/admin/users");
  };

  // Role cannot be changed
  const hasRoleChanged = () => false;

  if (fetching) {
    return (
      <EasySalonLayout
        sideNavItems={getAdminNavItems(user?.role || 'Easy Salon')}
        sideNavTitle="Easy Salon"
        sideNavSubtitle="Área Easy Salon"
      >
