          <p className="text-[13px] text-muted-foreground">Edite as informações do usuário</p>
        </div>
      </div>

      {/* Seção de informações do Tenant - somente leitura */}
      {originalUser?.role === UserRole.TENANT_ADMIN && tenantData && (
        <div className="bg-card border border-border rounded-lg mb-6">
          <div className="px-6 pt-6 pb-0">
            <h2 className="text-base font-semibold flex items-center gap-2">
              <Building2 className="h-5 w-5" />
              Informações do Tenant
            </h2>
          </div>
          <div className="p-6 space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="flex flex-col gap-[4px]">
                <Label className="text-muted-foreground">Nome do Tenant</Label>
                <div className="p-2 bg-muted rounded-md">
                  <p className="text-body font-medium">{tenantData.name}</p>
                </div>
              </div>

              <div className="flex flex-col gap-[4px]">
                <Label className="text-muted-foreground">Slug</Label>
                <div className="p-2 bg-muted rounded-md">
                  <p className="text-body font-medium">{tenantData.slug}</p>
                </div>
              </div>

              {tenantData.domain && (
                <div className="flex flex-col gap-[4px]">
                  <Label className="text-muted-foreground flex items-center gap-1">
                    <Globe className="h-3 w-3" />
                    Domínio
                  </Label>
                  <div className="p-2 bg-muted rounded-md">
                    <p className="text-body font-medium">{tenantData.domain}</p>
                  </div>
                </div>
              )}

              <div className="flex flex-col gap-[4px]">
                <Label className="text-muted-foreground">Status</Label>
                <div className="p-2 bg-muted rounded-md">
                  <div className="flex items-center gap-2">
                    {tenantData.active ? (
                      <>
                        <CheckCircle className="h-4 w-4 text-green-600" />
                        <span className="text-body font-medium text-green-600">Ativo</span>
                      </>
                    ) : (
                      <>
                        <XCircle className="h-4 w-4 text-red-600" />
                        <span className="text-body font-medium text-red-600">Inativo</span>
                      </>
                    )}
                  </div>
                </div>
              </div>

              {tenantData.subscriptionExpiresAt && (
                <div className="flex flex-col gap-[4px]">
                  <Label className="text-muted-foreground flex items-center gap-1">
                    <Calendar className="h-3 w-3" />
