import { NavItem, NavSection } from "@/types/navigation";
import { BarChart3, Briefcase, Building2, Calendar, ClipboardList, Settings as Cog, CreditCard, Scissors, UserCircle, Users } from "lucide-react";

// Função para obter navegação da área admin baseada no perfil do usuário
export const getAdminNavItems = (userRole: string): NavItem[] => {
  const baseItems: NavItem[] = [
    {
      title: "Salões",
      href: "/admin/salons",
      icon: Building2,
    },
  ];

  if (userRole === "Easy Salon" || userRole === "Tenant Admin") {
    const items: NavItem[] = [...baseItems];

    if (userRole === "Easy Salon") {
      // Dashboard first (only for Super Admin)
      items.unshift({
        title: "Dashboard",
        href: "/admin/dashboard",
        icon: BarChart3,
      });
    }

    items.push({
      title: "Gestão de Acesso",
      href: "/admin/users",
      icon: Users,
    });

    if (userRole === "Easy Salon") {
      items.push({
        title: "Especialidades",
        href: "/admin/specialties",
        icon: Briefcase,
      });
    }

    // TODO: Módulo financeiro não lançado ainda — remover comentário quando pronto
    // items.push({
    //   title: "Financeiro",
    //   href: "/admin/financial",
    //   icon: Wallet,
