// ─── Helper: Code Snippet Block ────────────────────────────────────────────────
function CodeBlock({ code }: { code: string }) {
  const [copied, setCopied] = useState(false);
  const copy = () => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 1500);
  };
  return (
    <div className="relative">
      <pre className="rounded-md bg-muted p-4 text-xs overflow-x-auto text-muted-foreground font-mono leading-relaxed whitespace-pre-wrap">
        {code}
      </pre>
      <button
        onClick={copy}
        className="absolute top-2 right-2 text-[10px] bg-background border border-border rounded px-2 py-0.5 hover:bg-muted transition-colors"
      >
        {copied ? "Copiado!" : "Copiar"}
      </button>
    </div>
  );
}

