// ─── Helper: Icon card ───────────────────────────────────────────────────────
function IconCard({ name, Icon }: { name: string; Icon: React.ComponentType<{ size?: number }> }) {
  const [copied, setCopied] = useState(false);
  const copy = () => {
    navigator.clipboard.writeText(name);
    setCopied(true);
    setTimeout(() => setCopied(false), 1200);
  };
  return (
    <button
      onClick={copy}
      title={copied ? "Copiado!" : `Copiar: ${name}`}
      className="flex flex-col items-center gap-1.5 p-3 rounded-lg border bg-card hover:bg-muted/60 hover:border-primary/30 transition-all group text-center"
    >
      <Icon size={20} />
      <span className={cn("text-[9px] font-mono leading-tight break-all", copied ? "text-primary font-semibold" : "text-muted-foreground")}>
        {copied ? "copiado!" : name.replace("Icon", "")}
      </span>
    </button>
  );
}

