                      </div>
                    </div>
                  ))}
                </div>
              </div>

              {/* Typography scale */}
              <div>
                <p className="text-xs font-semibold uppercase tracking-widest text-muted-foreground mb-3">Escala Tipográfica</p>
                <div className="border rounded-lg overflow-hidden">
                  {[
                    { cls: "text-page-title", label: "page-title", size: "20px / 700", example: "Título de Página" },
                    { cls: "text-section-title", label: "section-title", size: "18px / 600", example: "Título de Seção" },
                    { cls: "text-body", label: "body", size: "13px / 400", example: "Texto de corpo e listas" },
                    { cls: "text-button", label: "button", size: "13px / 500", example: "Rótulo de botão" },
                  ].map((t, i) => (
                    <div key={t.label} className={cn("flex items-center gap-4 px-4 py-3", i !== 0 && "border-t")}>
                      <code className="text-[10px] bg-muted px-1.5 py-0.5 rounded shrink-0 w-28 text-center">{t.label}</code>
                      <span className={t.cls}>{t.example}</span>
                      <span className="text-[10px] text-muted-foreground ml-auto shrink-0">{t.size}</span>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </Section>

          {/* ── ICONS ──────────────────────────────────────────────────────── */}
          <Section
            id="icons"
            title="Ícones"
            description="Biblioteca Lucide Icons. Importe diretamente de lucide-react. Clique em qualquer ícone para copiar o nome."            importPath="lucide-react"
          >
            <Tabs defaultValue="in-use">
              <TabsList className="mb-6">
                <TabsTrigger value="in-use">Em Uso ({ICONS_IN_USE.length})</TabsTrigger>
                <TabsTrigger value="available">Disponíveis</TabsTrigger>
              </TabsList>

              {/* Em uso */}
              <TabsContent value="in-use">
                <div className="mb-3 p-3 rounded-lg bg-muted/60 border text-xs text-muted-foreground">
                  <strong className="text-foreground">{ICONS_IN_USE.length} ícones</strong> ativamente importados no projeto. Clique para copiar o nome do ícone.
                </div>
                <div className="grid grid-cols-4 sm:grid-cols-6 md:grid-cols-8 lg:grid-cols-10 xl:grid-cols-12 gap-2">
                  {ICONS_IN_USE.map(({ name, Icon }) => (
                    <IconCard key={name} name={name} Icon={Icon} />
                  ))}
                </div>
                <div className="mt-4">
                  <CodeBlock code={`import { Calendar as IconCalendar, Check as IconCheck, Plus as IconPlus } from "lucide-react"

// Tamanho padrão recomendado
<IconCalendar size={16} />   // inline / nav
<IconCalendar size={20} />   // botões e headers
<IconCalendar size={24} />   // destaques

// Com className (tailwind)
<IconCalendar className="h-4 w-4 text-muted-foreground" />`} />
                </div>
              </TabsContent>

              {/* Disponíveis */}
              <TabsContent value="available">
                <div className="mb-3 p-3 rounded-lg bg-muted/60 border text-xs text-muted-foreground">
                  Ícones do Tabler <strong className="text-foreground">não utilizados ainda</strong> no projeto, mas disponíveis para uso imediato via import. Clique para copiar o nome.
                </div>
                <div className="space-y-8">
                  {ICONS_AVAILABLE.map(({ category, icons }) => (
                    <div key={category}>
                      <p className="text-xs font-semibold uppercase tracking-widest text-muted-foreground mb-3">{category}</p>
                      <div className="grid grid-cols-4 sm:grid-cols-6 md:grid-cols-8 lg:grid-cols-10 gap-2">
                        {icons.map(({ name, Icon }) => (
                          <IconCard key={name} name={name} Icon={Icon} />
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
                <div className="mt-6 p-3 rounded-lg border text-xs text-muted-foreground">
                  O Tabler possui +5.000 ícones. Consulte o catálogo completo em{" "}
                  <code className="bg-muted px-1 rounded">tabler.io/icons</code>.
                </div>
              </TabsContent>
            </Tabs>
          </Section>

          {/* Footer */}
          <div className="border-t pt-8 pb-16 text-xs text-muted-foreground space-y-1">
            <p>Esta página reflete os componentes reais de <code>src/components/ui/</code>.</p>
            <p>Qualquer alteração nos componentes pai é imediatamente refletida aqui.</p>
            <p className="text-[10px]">Rota: <code>/design-system</code> — uso interno, não indexada no menu.</p>
          </div>
        </main>
      </div>
    </TooltipProvider>
  );
}

