  warning:
    "!bg-[#FEF6E4] !border-[#EBB33A]/50 !text-[#C28604] [&_[data-icon]]:!text-[#C28604]",
  info:
    "!bg-[#F1F4FF] !border-[#007AFF]/50 !text-[#1166C3] [&_[data-icon]]:!text-[#1166C3]",
  loading:
    "!bg-card !border-border !text-muted-foreground",
}

const Toaster = ({ toastOptions, ...props }: ToasterProps) => {
  const theme: ToasterProps["theme"] = "light";

  return (
    <Sonner
      theme={theme}
      className="toaster group"
      {...props}
      toastOptions={{
        ...toastOptions,
        classNames: DS_TOAST_CLASS_NAMES,
      }}
    />
  )
}

export { Toaster, toast }

