// Global Subscription Manager Component
// Handles the modal visibility based on the singleton state
function GlobalSubscriptionManager() {
  const [isExpired, setIsExpired] = useState(subscriptionState.getExpired());
  const location = useLocation();
  const navigate = useNavigate();
  const { user } = useAuth(); // Need auth to know if we should bypass

  useEffect(() => {
    // Restore subscription state from localStorage on refresh
    const storedExpired = localStorage.getItem('subscriptionExpired');
    if (storedExpired === 'true') {
      subscriptionState.setExpired(true);
    }

    // Subscribe to singleton
    const unsubscribe = subscriptionState.subscribe((expired) => {
      setIsExpired(expired);
    });
    return unsubscribe;
  }, []);

  // Whitelist Logic
  const isWhitelisted =
    location.pathname.startsWith("/salon/my-plan") ||
    location.pathname.startsWith("/salon/plano") ||
    location.pathname.startsWith("/login") ||
    location.pathname.startsWith("/register") ||
    location.pathname.startsWith("/onboarding") ||
    location.pathname === "/"; 

  const isSalonRoute = location.pathname.startsWith("/salon/");

  const handleConfirm = () => {
    navigate("/salon/my-plan");
  };

  // Bypass logic for Super Admin (Easy Salon)
  const isSuperAdmin = user?.role === "Easy Salon";

  // Don't show if whitelisted or super admin
  if (isWhitelisted || isSuperAdmin) {
    return null;
  }

  return (
    <SubscriptionAlertModal
      isOpen={isExpired}
      onConfirm={handleConfirm}
    />
  );
}

