  UserPen as IconUserEdit, UserMinus as IconUserMinus, Wallet as IconWallet,
} from "lucide-react";

// ─── Helper: Code Snippet Block ────────────────────────────────────────────────
function CodeBlock({ code }: { code: string }) {
  const [copied, setCopied] = useState(false);
  const copy = () => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 1500);
  };
  return (
    <div className="relative">
      <pre className="rounded-md bg-muted p-4 text-xs overflow-x-auto text-muted-foreground font-mono leading-relaxed whitespace-pre-wrap">
        {code}
      </pre>
      <button
        onClick={copy}
        className="absolute top-2 right-2 text-[10px] bg-background border border-border rounded px-2 py-0.5 hover:bg-muted transition-colors"
      >
        {copied ? "Copiado!" : "Copiar"}
      </button>
    </div>
  );
}

// ─── Helper: Props Table ────────────────────────────────────────────────────────
interface PropRow {
  name: string;
  type: string;
  default?: string;
  description: string;
}
function PropsTable({ props }: { props: PropRow[] }) {
  return (
    <div className="overflow-x-auto">
      <table className="w-full text-xs border-collapse">
        <thead>
          <tr className="border-b bg-muted/50">
            <th className="text-left p-2 font-semibold text-foreground w-32">Prop</th>
            <th className="text-left p-2 font-semibold text-foreground w-48">Tipo</th>
            <th className="text-left p-2 font-semibold text-foreground w-24">Default</th>
            <th className="text-left p-2 font-semibold text-foreground">Descrição</th>
          </tr>
        </thead>
        <tbody>
          {props.map((p) => (
            <tr key={p.name} className="border-b hover:bg-muted/30 transition-colors">
              <td className="p-2 font-mono text-primary">{p.name}</td>
              <td className="p-2 font-mono text-muted-foreground">{p.type}</td>
              <td className="p-2 font-mono text-muted-foreground">{p.default ?? "—"}</td>
              <td className="p-2 text-muted-foreground">{p.description}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

// ─── Helper: Section wrapper ────────────────────────────────────────────────────
function Section({ id, title, description, importPath, children }: {
  id: string;
  title: string;
  description: string;
  importPath?: string;
  children: React.ReactNode;
}) {
  const [copiedImport, setCopiedImport] = useState(false);
  const copyImport = () => {
    navigator.clipboard.writeText(importPath ?? "");
    setCopiedImport(true);
    setTimeout(() => setCopiedImport(false), 1500);
  };
  return (
    <section id={id} className="scroll-mt-20 space-y-4">
      <div>
        <h2 className="text-xl font-semibold tracking-tight">{title}</h2>
        <p className="text-body text-muted-foreground mt-0.5">{description}</p>
        {importPath && (
          <div className="mt-2 flex flex-wrap gap-2">
            <div className="inline-flex items-center gap-2 rounded-md bg-muted px-3 py-1.5 font-mono text-xs text-muted-foreground border border-dashed">
              <span className="select-all whitespace-pre">{importPath}</span>
              <button
                onClick={copyImport}
                className="ml-1 text-[10px] bg-background border border-border rounded px-1.5 py-0.5 hover:bg-muted transition-colors shrink-0"
              >
                {copiedImport ? "Copiado!" : "Copiar"}
              </button>
            </div>
          </div>
        )}
      </div>
      <Separator />
      {children}
    </section>
  );
}

// ─── Helper: Preview + Code side-by-side ───────────────────────────────────────
